, '[{"role":"Head of Data Strategy & Sourcing"}]', 'not_started', 'pending', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-11 18:17:53.251044+00', '2026-03-11 18:17:53.251044+00', '{}') ON CONFLICT (id) DO NOTHING;
