a competitive edge for your revenue prediction models and earnings surprise detection.', '[{"id":"d924576f-1bb9-4fb5-9fe8-661dc43714ef","influence":"Unknown","name":"Steven Sellers","title":null},{"id":"10ab4656-f378-4c50-8543-0ce99edff3c3","influence":"Unknown","name":"Jack Dong","title":null},{"id":"52b75adc-6db6-49c9-bc9f-3079117311f4","influence":"Unknown","name":"Lyoe Lee","title":null}]', '[{"role":"Quantitative Analyst, Portfolio Manager, Head of Research"}]', 'not_started', 'pending', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-13 02:54:29.782648+00', '2026-03-13 02:54:29.782648+00', '{"coverage_overlap_score":56,"evidence_summary":"Citadel holds significant positions in large-cap technology and healthcare companies that are major government contractors or suppliers.","product_relevance_score":80,"sector_relevance":["Technology","Healthcare"],"supporting_companies":["NVIDIA CORP","TESLA INC","APPLE INC","MICROSOFT CORP","UNITEDHEALTH GROUP INC"]}') ON CONFLICT (id) DO NOTHING;
