INSERT INTO campaign_targets (id, campaign_id, client_id, prospect_name, prospect_type, is_existing_client, fit_score, fit_rationale, recommended_approach, recommended_messaging, recommended_contacts, target_personas, status, outreach_status, notes, owner_id, opportunity_id, contacted_at, responded_at, meeting_booked_at, created_at, updated_at, product_fit_analysis) VALUES ('fa7f9bcb-4fcc-41f8-ba58-70c4ae425c33', '842109f6-9292-4b3a-bda2-0f0ac04dc1ed', '0024e5a6-5d91-403a-88d4-fcd73b23faa6', NULL, NULL, 'false', 74, '{"best_persona":"Portfolio Manager, Head of Research, Quantitative Analyst","evidence_of_fit":"King Street''s portfolio shows significant direct holdings in companies like Boeing Co (39.81% and 32.69% total exposure), which are heavily dependent on government contracts and spending. Their exposure to PG&E Corp (31.35%) also indicates an interest in regulated utilities, which often have government-related revenue streams.","opportunity_type":"new_opportunity","product_relevance_rationale":"Forward-Looking Receivables data is highly relevant to King Street given their substantial direct investment in Boeing Co. This data can provide predictive signals on upcoming government contract awards and spending commitments, directly impacting Boeing''s future revenue and stock performance. Furthermore, insights into government spending could be valuable for their PG&E Corp holdings, as utilities often operate under government regulation and contracts.","scores":{"conversion_likelihood":85,"product_relevance":85,"relationship_strength":50,"strategic_fit":80,"timing_signal":50},"why_now":"No specific timing signal, but an active opportunity exists."}', 'Schedule a discovery call to demonstrate how Forward-Looking Receivables data can enhance their models for Boeing Co and other government-dependent holdings.', 'King Street, your significant positions in companies like Boeing Co and PG&E Corp suggest a keen interest in sectors influenced by government spending. Our Forward-Looking Receivables data provides predictive signals on upcoming government contract awards, offering a unique edge for revenue prediction models and earnings surprise detection for your portfolio companies.', '[{"id":"496a2e70-c5ae-4a0f-afe1-6dfe1e219630","influence":"Unknown","name":"Philip DiLemme","title":"Data Sourcing"},{"id":"56290519-6805-4eff-896b-5ed8bb3c04d9","influence":"Unknown","name":"Philip DiLemme","title":null}]', '[{"role":"Portfolio Manager, Head of Research, Quantitative Analyst"}]', 'not_started', 'pending', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-13 02:54:29.782648+00', '2026-03-13 02:54:29.782648+00', '{"coverage_overlap_score":10,"evidence_summary":"King Street has significant direct holdings in Boeing Co and PG&E Corp, both of which are heavily influenced by government contracts and spending.","product_relevance_score":85,"sector_relevance":["Aerospace & Defense","Utilities"],"supporting_companies":["BOEING CO","PG&E CORP"]}') ON CONFLICT (id) DO NOTHING;
INSERT INTO campaign_targets (id, campaign_id, client_id, prospect_name, prospect_type, is_existing_client, fit_score, fit_rationale, recommended_approach, recommended_messaging, recommended_contacts, target_personas, status, outreach_status, notes, owner_id, opportunity_id, contacted_at, responded_at, meeting_booked_at, created_at, updated_at, product_fit_analysis) VALUES ('535f2440-127e-4615-b129-6fa6bd6b992e', '842109f6-9292-4b3a-bda2-0f0ac04dc1ed', 'db49ca3f-c304-4ebf-ba50-a48386441ee4', NULL, NULL, 'false', 73, '{"best_persona":"Quantitative Researcher, Portfolio Manager, Data Scientist","evidence_of_fit":"Bridgewater Associates has significant exposure to the Technology sector, including companies like Microsoft Corp (6.77%), NVIDIA Corp (4.95%), and Salesforce Inc (3.66%). They also hold Johnson & Johnson (1.95%) in the Healthcare sector. Many companies in these sectors, particularly large technology firms, engage in significant government contracting.","opportunity_type":"new_opportunity","product_relevance_rationale":"Forward-Looking Receivables data can provide valuable insights for Bridgewater''s holdings in large technology companies like Microsoft and Salesforce, which often secure substantial government contracts. This data can be used for revenue prediction models and detecting earnings surprises related to government spending, offering a unique predictive edge for their portfolio.","scores":{"conversion_likelihood":85,"product_relevance":80,"relationship_strength":50,"strategic_fit":80,"timing_signal":50},"why_now":"No specific timing signal, but an active opportunity exists."}', 'Propose a tailored data sample and a use-case discussion focusing on their tech holdings'' government contract exposure.', 'Bridgewater, your substantial positions in technology leaders like Microsoft and Salesforce suggest a focus on companies with significant enterprise and government relationships. Our Forward-Looking Receivables data offers predictive signals on upcoming government contract awards, which could be instrumental for enhancing revenue prediction models and identifying earnings surprises for your key holdings.', '[{"id":"6494ccbe-ed81-4aaf-b95c-9687d89a0db7","influence":"Unknown","name":"Jason Koulouras","title":"Data Scout"}]', '[{"role":"Quantitative Researcher, Portfolio Manager, Data Scientist"}]', 'not_started', 'pending', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-13 02:54:29.782648+00', '2026-03-13 02:54:29.782648+00', '{"coverage_overlap_score":38,"evidence_summary":"Bridgewater has significant holdings in large technology and healthcare companies that are often involved in government contracting.","product_relevance_score":80,"sector_relevance":["Technology","Healthcare"],"supporting_companies":["MICROSOFT CORP","SALESFORCE INC","JOHNSON & JOHNSON"]}') ON CONFLICT (id) DO NOTHING;
