ediction models and earnings surprise detection.', '[{"id":"cad39c11-5be3-4abb-a916-9469e90c6861","influence":"Unknown","name":"Wara Tongprasit","title":null}]', '[{"role":"Portfolio Manager, Quantitative Analyst, Sector Specialist (Tech, Healthcare)"}]', 'not_started', 'pending', NULL, NULL, NULL, NULL, NULL, NULL, '2026-03-13 02:54:29.782648+00', '2026-03-13 02:54:29.782648+00', '{"coverage_overlap_score":56,"evidence_summary":"Morgan Stanley holds significant positions in large-cap technology and healthcare companies that are major government contractors.","product_relevance_score":80,"sector_relevance":["Technology","Healthcare"],"supporting_companies":["APPLE INC","MICROSOFT CORP","NVIDIA CORP","ELI LILLY & CO COM"]}') ON CONFLICT (id) DO NOTHING;
